#include<bits/stdc++.h>
using namespace std;

const int N = 1e3 + 5, M = 1e3 + 5;
int n, m, ans;
bool d[N][N];
int in[N], topo[N], dp[N], vis[N], a[N];

bool toposort()
{
	int t = 0;
	queue<pair<int, int> > q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(make_pair(i, 1));
	while(!q.empty())
	{
		auto u = q.front();
		q.pop();
        ans = max(ans, u.second);
		for(int v = 1; v <= n; v++)
		{
			if(!d[u.first][v]) continue;
			in[v]--;
			if(!in[v]) q.push(make_pair(v, u.second + 1));
		}
	}
	return t == n;
}

int main()
{
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int s;
		cin >> s;
		memset(vis, 0, sizeof vis);
		for(int i = 1; i <= s; i++)
		{
			cin >> a[i];
			vis[a[i]] = 1;
		}
		for(int j = a[1]; j <= a[s]; j++)
		{
			if(vis[j]) continue;
			for(int i = 1; i <= s; i++)
				d[j][a[i]] = 1;
		}
	}
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= n; j++)
			in[j] += d[i][j];
	toposort();
	cout << ans << endl;
	return 0;
}
